import styled from "styled-components";
import Ul from "smart-react-components/element/Ul";
export default styled(Ul)(({ theme, sub, linkList, listStyle }) => `
    list-style: ${listStyle ? listStyle : (sub ? "circle" : "initial")};
    margin-left: 1.15rem;

    > li {
        padding-bottom: ${theme.src.length["1"]};
        color: ${linkList ? theme.src.color.dark : theme.src.color.darkblue};
        word-break: break-all;
        
        span {
            color: ${theme.src.color.dark};
        }

        ul {
            padding-top: ${theme.src.length["1"]};
        }
    }
`);
